import json
from elasticsearch import Elasticsearch

# Create an instance of the Elasticsearch client
es = Elasticsearch(['http://localhost:9200'])

# Define a function to index a document
def index_document(index, doc):
    es.index(index=index, body=json.dumps(doc))

# Define a function to search for documents
def search_documents(query, index):
    result = es.search(index=index, q=query)
    return [hit['_source'] for hit in result['hits']['hits']]

# Define a function to aggregate logs
def aggregate_logs(query, index, field):
    result = es.search(index=index, body={
        "size": 0,
        "aggs": {
            "group_by_" + field: {
                "terms": {
                    "field": field,
                    "size": 10000
                }
            }
        },
        "query": {
            "bool": {
                "must": [
                    {
                        "query_string": {
                            "query": query
                        }
                    }
                ]
            }
        }
    })
    return result['aggregations']['group_by_' + field]['buckets']

# Example usage of the functions
index_document('my_index', {'name': 'John Doe', 'age': 30})
search_results = search_documents('John', 'my_index')
print(search_results)
aggregation_results = aggregate_logs('log:error', 'my_index', 'user')
print(aggregation_results)